    18→  useTypeahead,
    19→  safePolygon,
    20→} from '../../floating-ui-react';
    21→import { MenuRootContext, useMenuRootContext } from './MenuRootContext';
    22→import { MenubarContext, useMenubarContext } from '../../menubar/MenubarContext';
    23→import { useTransitionStatus } from '../../utils/useTransitionStatus';
    24→import { PATIENT_CLICK_THRESHOLD, TYPEAHEAD_RESET_MS } from '../../utils/constants';
    25→import { useOpenChangeComplete } from '../../utils/useOpenChangeComplete';
    26→import { useDirection } from '../../direction-provider/DirectionContext';
    27→import { useScrollLock } from '../../utils/useScrollLock';
    28→import { useOpenInteractionType } from '../../utils/useOpenInteractionType';
    29→import {
    30→  type BaseOpenChangeReason,
    31→  translateOpenChangeReason,
    32→} from '../../utils/translateOpenChangeReason';
    33→import {
    34→  ContextMenuRootContext,
    35→  useContextMenuRootContext,
    36→} from '../../context-menu/root/ContextMenuRootContext';
    37→import { useMenuSubmenuRootContext } from '../submenu-root/MenuSubmenuRootContext';
    38→import { useMixedToggleClickHandler } from '../../utils/useMixedToggleClickHander';
    39→import { mergeProps } from '../../merge-props';
    40→
    41→const EMPTY_ARRAY: never[] = [];
    42→const EMPTY_REF = { current: false };
    43→
    44→/**
    45→ * Groups all parts of the menu.
    46→ * Doesn’t render its own HTML element.
    47→ *
    48→ * Documentation: [Base UI Menu](https://base-ui.com/react/components/menu)
    49→ */
    50→export const MenuRoot: React.FC<MenuRoot.Props> = function MenuRoot(props) {
    51→  const {
    52→    children,
    53→    open: openProp,
    54→    onOpenChange,
    55→    onOpenChangeComplete,
    56→    defaultOpen = false,
    57→    disabled = false,
    58→    modal: modalProp,
    59→    loop = true,
    60→    orientation = 'vertical',
    61→    actionsRef,
    62→    openOnHover: openOnHoverProp,
    63→    delay = 100,
    64→    closeDelay = 0,
    65→    closeParentOnEsc = true,
    66→  } = props;
    67→
    68→  const [triggerElement, setTriggerElement] = React.useState<HTMLElement | null>(null);
    69→  const [positionerElement, setPositionerElementUnwrapped] = React.useState<HTMLElement | null>(
    70→    null,
    71→  );
    72→  const [instantType, setInstantType] = React.useState<'dismiss' | 'click' | 'group'>();
    73→  const [hoverEnabled, setHoverEnabled] = React.useState(true);
    74→  const [activeIndex, setActiveIndex] = React.useState<number | null>(null);
    75→  const [lastOpenChangeReason, setLastOpenChangeReason] =
    76→    React.useState<MenuRoot.OpenChangeReason | null>(null);
    77→  const [stickIfOpen, setStickIfOpen] = React.useState(true);
    78→  const [allowMouseEnterState, setAllowMouseEnterState] = React.useState(false);
    79→
    80→  const openEventRef = React.useRef<Event | null>(null);
    81→  const popupRef = React.useRef<HTMLElement>(null);
    82→  const positionerRef = React.useRef<HTMLElement | null>(null);
    83→
    84→  const stickIfOpenTimeout = useTimeout();
    85→  const contextMenuContext = useContextMenuRootContext(true);
    86→  const isSubmenu = useMenuSubmenuRootContext();
    87→
    88→  let parent: MenuParent;
    89→  {
    90→    const parentContext = useMenuRootContext(true);
    91→    const menubarContext = useMenubarContext(true);
    92→
    93→    if (isSubmenu && parentContext) {
    94→      parent = {
    95→        type: 'menu',
    96→        context: parentContext,
    97→      };
    98→    } else if (menubarContext) {
    99→      parent = {
   100→        type: 'menubar',
   101→        context: menubarContext,
   102→      };
   103→    } else if (contextMenuContext) {
   104→      parent = {
   105→        type: 'context-menu',
   106→        context: contextMenuContext,
   107→      };
   108→    } else {
   109→      parent = {
   110→        type: undefined,
   111→      };
   112→    }
   113→  }
   114→
   115→  let rootId = useId();
   116→
   117→  if (parent.type !== undefined) {
   118→    rootId = parent.context.rootId;
   119→  }
   120→
   121→  const modal =
   122→    (parent.type === undefined || parent.type === 'context-menu') && (modalProp ?? true);
   123→
   124→  // If this menu is a submenu, it should inherit `allowMouseEnter` from its
   125→  // parent. Otherwise it manages the state on its own.
   126→  const allowMouseEnter =
   127→    parent.type === 'menu' ? parent.context.allowMouseEnter : allowMouseEnterState;
   128→  const setAllowMouseEnter =
   129→    parent.type === 'menu' ? parent.context.setAllowMouseEnter : setAllowMouseEnterState;
   130→
   131→  if (process.env.NODE_ENV !== 'production') {
   132→    if (parent.type !== undefined && modalProp !== undefined) {
   133→      console.warn(
   134→        'Base UI: The `modal` prop is not supported on nested menus. It will be ignored.',
   135→      );
   136→    }
   137→  }
   138→
   139→  const openOnHover =
   140→    openOnHoverProp ??
   141→    (parent.type === 'menu' || (parent.type === 'menubar' && parent.context.hasSubmenuOpen));
   142→
   143→  const [open, setOpenUnwrapped] = useControlled({
   144→    controlled: openProp,
   145→    default: defaultOpen,
   146→    name: 'MenuRoot',
   147→    state: 'open',
   148→  });
   149→
   150→  const allowOutsidePressDismissalRef = React.useRef(parent.type !== 'context-menu');
   151→  const allowOutsidePressDismissalTimeout = useTimeout();
   152→
   153→  React.useEffect(() => {
   154→    if (!open) {
   155→      openEventRef.current = null;
   156→    }
   157→
   158→    if (parent.type !== 'context-menu') {
   159→      return;
   160→    }
   161→
   162→    if (!open) {
   163→      allowOutsidePressDismissalTimeout.clear();
   164→      allowOutsidePressDismissalRef.current = false;
   165→      return;
   166→    }
   167→
