   172→      allowOutsidePressDismissalRef.current = true;
   173→    });
   174→  }, [allowOutsidePressDismissalTimeout, open, parent.type]);
   175→
   176→  const setPositionerElement = React.useCallback((value: HTMLElement | null) => {
   177→    positionerRef.current = value;
   178→    setPositionerElementUnwrapped(value);
   179→  }, []);
