   181→  const { mounted, setMounted, transitionStatus } = useTransitionStatus(open);
   182→  const {
   183→    openMethod,
   184→    triggerProps: interactionTypeProps,
   185→    reset: resetOpenInteractionType,
   186→  } = useOpenInteractionType(open);
   187→
   188→  useScrollLock({
   189→    enabled: open && modal && lastOpenChangeReason !== 'trigger-hover' && openMethod !== 'touch',
   190→    mounted,
   191→    open,
   192→    referenceElement: positionerElement,
   193→  });
   194→
