   455→            setHoverEnabled(false);
   456→          }
   457→        },
   458→        onMouseMove() {
   459→          setAllowMouseEnter(true);
   460→        },
   461→        onClick() {
   462→          if (openOnHover) {
   463→            setHoverEnabled(false);
   464→          }
   465→        },
   466→      }),
   467→    [getFloatingProps, openOnHover, parent.type, setAllowMouseEnter],
   468→  );
   469→
   470→  const itemProps = React.useMemo(() => getItemProps(), [getItemProps]);
   471→
   472→  const context = React.useMemo(
   473→    () => ({
   474→      activeIndex,
   475→      setActiveIndex,
   476→      allowMouseUpTriggerRef: parent.type ? parent.context.allowMouseUpTriggerRef : EMPTY_REF,
   477→      floatingRootContext,
   478→      itemProps,
   479→      popupProps,
   480→      triggerProps,
   481→      itemDomElements,
   482→      itemLabels,
   483→      mounted,
   484→      open,
   485→      popupRef,
   486→      positionerRef,
   487→      setOpen,
   488→      setPositionerElement,
   489→      triggerElement,
   490→      setTriggerElement,
   491→      transitionStatus,
   492→      lastOpenChangeReason,
   493→      instantType,
   494→      onOpenChangeComplete,
   495→      setHoverEnabled,
   496→      typingRef,
   497→      modal,
   498→      disabled,
   499→      parent,
   500→      rootId,
   501→      allowMouseEnter,
   502→      setAllowMouseEnter,
   503→    }),
   504→    [
   505→      activeIndex,
   506→      floatingRootContext,
   507→      itemProps,
   508→      popupProps,
   509→      triggerProps,
   510→      itemDomElements,
   511→      itemLabels,
   512→      mounted,
   513→      open,
   514→      positionerRef,
   515→      setOpen,
   516→      transitionStatus,
   517→      triggerElement,
   518→      setPositionerElement,
   519→      lastOpenChangeReason,
   520→      instantType,
   521→      onOpenChangeComplete,
   522→      modal,
   523→      disabled,
   524→      parent,
   525→      rootId,
   526→      allowMouseEnter,
   527→      setAllowMouseEnter,
   528→    ],
   529→  );
   530→
   531→  const content = <MenuRootContext.Provider value={context}>{children}</MenuRootContext.Provider>;
   532→
   533→  if (parent.type === undefined || parent.type === 'context-menu') {
   534→    // set up a FloatingTree to provide the context to nested menus
   535→    return <FloatingTree>{content}</FloatingTree>;
   536→  }
   537→
   538→  return content;
   539→};
   540→
   541→export namespace MenuRoot {
   542→  export interface Props {
   543→    children: React.ReactNode;
   544→    /**
   545→     * Whether the menu is initially open.
   546→     *
   547→     * To render a controlled menu, use the `open` prop instead.
   548→     * @default false
   549→     */
   550→    defaultOpen?: boolean;
   551→    /**
   552→     * Whether to loop keyboard focus back to the first item
   553→     * when the end of the list is reached while using the arrow keys.
   554→     * @default true
   555→     */
   556→    loop?: boolean;
   557→    /**
   558→     * Determines if the menu enters a modal state when open.
   559→     * - `true`: user interaction is limited to the menu: document page scroll is locked and and pointer interactions on outside elements are disabled.
