   561→     * @default true
   562→     */
   563→    modal?: boolean;
   564→    /**
   565→     * Event handler called when the menu is opened or closed.
   566→     */
   567→    onOpenChange?: (
   568→      open: boolean,
   569→      event: Event | undefined,
   570→      reason: OpenChangeReason | undefined,
   571→    ) => void;
   572→    /**
   573→     * Event handler called after any animations complete when the menu is closed.
   574→     */
   575→    onOpenChangeComplete?: (open: boolean) => void;
   576→    /**
   577→     * Whether the menu is currently open.
   578→     */
   579→    open?: boolean;
   580→    /**
   581→     * The visual orientation of the menu.
   582→     * Controls whether roving focus uses up/down or left/right arrow keys.
   583→     * @default 'vertical'
   584→     */
   585→    orientation?: Orientation;
   586→    /**
   587→     * Whether the component should ignore user interaction.
   588→     * @default false
   589→     */
