   604→    /**
   605→     * How long to wait before closing the menu that was opened on hover.
   606→     * Specified in milliseconds.
   607→     *
   608→     * Requires the `openOnHover` prop.
   609→     * @default 0
   610→     */
   611→    closeDelay?: number;
   612→    /**
   613→     * Whether the menu should also open when the trigger is hovered.
   614→     */
   615→    openOnHover?: boolean;
   616→    /**
   617→     * A ref to imperative actions.
   618→     * - `unmount`: When specified, the menu will not be unmounted when closed.
   619→     * Instead, the `unmount` function must be called to unmount the menu manually.
   620→     * Useful when the menu's animation is controlled by an external library.
   621→     */
   622→    actionsRef?: React.RefObject<Actions>;
   623→  }
   624→
   625→  export interface Actions {
   626→    unmount: () => void;
   627→  }
   628→
   629→  export type OpenChangeReason = BaseOpenChangeReason | 'sibling-open';
   630→
   631→  export type Orientation = 'horizontal' | 'vertical';
   632→
   633→  export interface Actions {
   634→    unmount: () => void;
   635→  }
   636→}
   637→
   638→export type MenuParent =
   639→  | {
   640→      type: 'menu';
   641→      context: MenuRootContext;
   642→    }
   643→  | {
   644→      type: 'menubar';
   645→      context: MenubarContext;
   646→    }
   647→  | {
   648→      type: 'context-menu';
   649→      context: ContextMenuRootContext;
   650→    }
   651→  | {
   652→      type: 'nested-context-menu';
   653→      context: ContextMenuRootContext;
   654→      menuContext: MenuRootContext;
   655→    }
   656→  | {
   657→      type: undefined;
   658→    };
