     1→import * as React from 'react';
     2→import { isHTMLElement } from '@floating-ui/utils/dom';
     3→import { useLatestRef } from '@base-ui-components/utils/useLatestRef';
     4→import { useEventCallback } from '@base-ui-components/utils/useEventCallback';
     5→import { useIsoLayoutEffect } from '@base-ui-components/utils/useIsoLayoutEffect';
     6→import {
     7→  activeElement,
     8→  contains,
     9→  getDocument,
    10→  isTypeableCombobox,
    11→  isVirtualClick,
    12→  isVirtualPointerEvent,
    13→  stopEvent,
    14→  getFloatingFocusElement,
    15→  isIndexOutOfListBounds,
    16→  getMinListIndex,
    17→  getMaxListIndex,
    18→  getGridNavigatedIndex,
    19→  isListIndexDisabled,
    20→  createGridCellMap,
    21→  getGridCellIndices,
    22→  getGridCellIndexOfCorner,
    23→  findNonDisabledListIndex,
    24→} from '../utils';
    25→
    26→import { useFloatingParentNodeId, useFloatingTree } from '../components/FloatingTree';
    27→import type { Dimensions, ElementProps, FloatingRootContext } from '../types';
    28→import { enqueueFocus } from '../utils/enqueueFocus';
    29→import { ARROW_UP, ARROW_DOWN, ARROW_RIGHT, ARROW_LEFT } from '../utils/constants';
    30→
    31→export const ESCAPE = 'Escape';
    32→
    33→function doSwitch(
    34→  orientation: UseListNavigationProps['orientation'],
    35→  vertical: boolean,
    36→  horizontal: boolean,
    37→) {
    38→  switch (orientation) {
    39→    case 'vertical':
    40→      return vertical;
    41→    case 'horizontal':
    42→      return horizontal;
    43→    default:
    44→      return vertical || horizontal;
    45→  }
    46→}
    47→
    48→function isMainOrientationKey(key: string, orientation: UseListNavigationProps['orientation']) {
    49→  const vertical = key === ARROW_UP || key === ARROW_DOWN;
    50→  const horizontal = key === ARROW_LEFT || key === ARROW_RIGHT;
    51→  return doSwitch(orientation, vertical, horizontal);
    52→}
    53→
    54→function isMainOrientationToEndKey(
    55→  key: string,
    56→  orientation: UseListNavigationProps['orientation'],
    57→  rtl: boolean,
    58→) {
    59→  const vertical = key === ARROW_DOWN;
    60→  const horizontal = rtl ? key === ARROW_LEFT : key === ARROW_RIGHT;
    61→  return (
    62→    doSwitch(orientation, vertical, horizontal) || key === 'Enter' || key === ' ' || key === ''
    63→  );
    64→}
    65→
    66→function isCrossOrientationOpenKey(
    67→  key: string,
    68→  orientation: UseListNavigationProps['orientation'],
    69→  rtl: boolean,
    70→) {
    71→  const vertical = rtl ? key === ARROW_LEFT : key === ARROW_RIGHT;
    72→  const horizontal = key === ARROW_DOWN;
    73→  return doSwitch(orientation, vertical, horizontal);
    74→}
    75→
    76→function isCrossOrientationCloseKey(
    77→  key: string,
    78→  orientation: UseListNavigationProps['orientation'],
    79→  rtl: boolean,
    80→  cols?: number,
    81→) {
    82→  const vertical = rtl ? key === ARROW_RIGHT : key === ARROW_LEFT;
    83→  const horizontal = key === ARROW_UP;
    84→  if (orientation === 'both' || (orientation === 'horizontal' && cols && cols > 1)) {
    85→    return key === ESCAPE;
    86→  }
    87→  return doSwitch(orientation, vertical, horizontal);
    88→}
    89→
    90→export interface UseListNavigationProps {
    91→  /**
    92→   * A ref that holds an array of list items.
    93→   * @default empty list
    94→   */
    95→  listRef: React.MutableRefObject<Array<HTMLElement | null>>;
    96→  /**
    97→   * The index of the currently active (focused or highlighted) item, which may
    98→   * or may not be selected.
    99→   * @default null
   100→   */
   101→  activeIndex: number | null;
   102→  /**
   103→   * A callback that is called when the user navigates to a new active item,
   104→   * passed in a new `activeIndex`.
   105→   */
   106→  onNavigate?: (activeIndex: number | null) => void;
   107→  /**
   108→   * Whether the Hook is enabled, including all internal Effects and event
   109→   * handlers.
   110→   * @default true
   111→   */
   112→  enabled?: boolean;
   113→  /**
   114→   * The currently selected item index, which may or may not be active.
   115→   * @default null
   116→   */
   117→  selectedIndex?: number | null;
   118→  /**
   119→   * Whether to focus the item upon opening the floating element. 'auto' infers
   120→   * what to do based on the input type (keyboard vs. pointer), while a boolean
   121→   * value will force the value.
   122→   * @default 'auto'
   123→   */
   124→  focusItemOnOpen?: boolean | 'auto';
   125→  /**
   126→   * Whether hovering an item synchronizes the focus.
   127→   * @default true
   128→   */
   129→  focusItemOnHover?: boolean;
   130→  /**
   131→   * Whether pressing an arrow key on the navigation’s main axis opens the
   132→   * floating element.
   133→   * @default true
   134→   */
