   804→      focusItemOnOpenRef.current = focusItemOnOpen;
   805→      if (focusItemOnOpen === 'auto' && isVirtualPointerEvent(event.nativeEvent)) {
   806→        focusItemOnOpenRef.current = true;
   807→      }
   808→    }
   809→
   810→    return {
   811→      ...ariaActiveDescendantProp,
   812→      onKeyDown(event) {
   813→        isPointerModalityRef.current = false;
   814→
   815→        const isArrowKey = event.key.startsWith('Arrow');
   816→        const isParentCrossOpenKey = isCrossOrientationOpenKey(
   817→          event.key,
   818→          getParentOrientation(),
   819→          rtl,
   820→        );
   821→        const isMainKey = isMainOrientationKey(event.key, orientation);
   822→        const isNavigationKey =
   823→          (nested ? isParentCrossOpenKey : isMainKey) ||
   824→          event.key === 'Enter' ||
   825→          event.key.trim() === '';
   826→
   827→        if (virtual && open) {
   828→          return commonOnKeyDown(event);
   829→        }
   830→
   831→        // If a floating element should not open on arrow key down, avoid
   832→        // setting `activeIndex` while it's closed.
   833→        if (!open && !openOnArrowKeyDown && isArrowKey) {
   834→          return undefined;
   835→        }
