import * as React from 'react';
import { expect } from 'chai';
import { act, waitFor, screen, fireEvent } from '@mui/internal-test-utils';
import { Menu } from '@base-ui-components/react/menu';
import userEvent from '@testing-library/user-event';
import { createRenderer } from '#test-utils';

describe('<Menu.Root /> - Shift+Tab bug', () => {
  beforeEach(() => {
    globalThis.BASE_UI_ANIMATIONS_DISABLED = true;
  });

  const { render } = createRenderer();

  it('should close submenu when pressing Shift+Tab from a submenu item', async () => {
    const { getByText, queryByText } = await render(
      <Menu.Root open>
        <Menu.Portal>
          <Menu.Positioner>
            <Menu.Popup>
              <Menu.Item>Item 1</Menu.Item>
              <Menu.SubmenuRoot>
                <Menu.SubmenuTrigger>Item 2</Menu.SubmenuTrigger>
                <Menu.Portal>
                  <Menu.Positioner>
                    <Menu.Popup>
                      <Menu.Item>Subitem 2.1</Menu.Item>
                      <Menu.Item>Subitem 2.2</Menu.Item>
                    </Menu.Popup>
                  </Menu.Positioner>
                </Menu.Portal>
              </Menu.SubmenuRoot>
              <Menu.Item>Item 3</Menu.Item>
            </Menu.Popup>
          </Menu.Positioner>
        </Menu.Portal>
      </Menu.Root>
    );

    const submenuTrigger = getByText('Item 2');

    // Focus on submenu trigger
    await act(async () => {
      submenuTrigger.focus();
    });

    // Open submenu with ArrowRight
    await userEvent.keyboard('{ArrowRight}');

    // Wait for submenu item to be focused
    const subitem1 = getByText('Subitem 2.1');
    await waitFor(() => {
      expect(subitem1).toHaveFocus();
    });

    // Verify submenu is open
    expect(queryByText('Subitem 2.1')).to.exist;
    expect(queryByText('Subitem 2.2')).to.exist;

    // Press Shift+Tab to move focus back to parent menu
    await userEvent.keyboard('{Shift>}{Tab}{/Shift}');

    // Focus should return to submenu trigger
    await waitFor(() => {
      expect(submenuTrigger).toHaveFocus();
    });

    // BUG: The submenu should be closed now (like when pressing ArrowLeft),
    // but it stays open
    // This assertion will fail with the bug:
    await waitFor(() => {
      expect(queryByText('Subitem 2.1')).to.not.exist;
    }, { timeout: 1000 });
  });
});

