                  <Menu.Item onClick={() => handleClick()}>Item One</Menu.Item>
                  <Menu.Item onClick={() => handleClick()}>Item Two</Menu.Item>
                  <Menu.Item onClick={() => handleClick()}>Item Three</Menu.Item>
                </Menu.Popup>
              </Menu.Positioner>
            </Menu.Portal>
