    ariaActiveDescendantProp,
    commonOnKeyDown,
    disabledIndicesRef,
    focusItemOnOpen,
    listRef,
    nested,
    onNavigate,
    onOpenChange,
    open,
    openOnArrowKeyDown,
    orientation,
    getParentOrientation,
    rtl,
    selectedIndex,
    virtual,
  ]);

  return React.useMemo(
    () => (enabled ? { reference, floating, item } : {}),
    [enabled, reference, floating, item],
  );
}

