                    aria-selected={activeIndex === index}
                    key={string}
                    tabIndex={-1}
                    {...getItemProps({
                      ref(node: HTMLLIElement) {
                        listRef.current[index] = node;
                      },
                    })}
                  >
                    {string}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </React.Fragment>
      );
    }

    render(<App />);

    act(() => {
      screen.getByRole('combobox').focus();
